def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    primes_cache = {}
    def is_prime(n):
        if n < 2:
            return False
        if n in primes_cache:
            return primes_cache[n]
        for x in range(2, int(n**0.5) + 1):
            if n % x == 0:
                primes_cache[n] = False
                return False
        primes_cache[n] = True
        return True
    def collatz_steps(n):
        steps = 0
        while n != 1 and steps < 100:
            if n % 2 == 0:
                n = n // 2
            else:
                n = 3*n + 1
            steps += 1
        return steps
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf if item > cap else 1000
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.1:
            series_sum = 0
            for a in range(1, 11):
                for b in range(1, 6):
                    val = (np.tan((cap + a*b)/ (a + b + 1)) + 1.5) * np.exp(-ratio*a*b)
                    series_sum += val/(a+b)
            score += series_sum
            prime_factors = [p for p in range(2, int(cap//1.5)+1) if cap % p == 0 and is_prime(p)]
            for pf in prime_factors:
                score += np.power(pf, 0.6) * (np.sin(pf*ratio)+1.3)
            if cap % 7 == 0:
                score *= 1.15
            if collatz_steps(int(cap)) < 30:
                score += 25
        elif 0.1 <= ratio < 0.35:
            base = np.log1p(ratio*cap)*10
            harmonic = 0
            for i in range(1, int(cap // 2)+1):
                harmonic += 1 / i
            score += base + harmonic * 0.5
            for d in range(2,10):
                if cap % d == 0:
                    score += (np.sqrt(d) * ratio * 3)
            if cap % 8 == 0:
                score *= 0.85
            if is_prime(int(cap)):
                score += 20
        elif 0.35 <= ratio <= 0.65:
            wave_sum = 0
            for f in range(1, 12):
                wave_sum += np.sin(ratio * np.pi * f) * np.cos(cap / (f + 1))
            score += wave_sum * 5
            for g in range(2, int(min(15, cap))):
                if cap % g == 0 and (g % 5 == 2 or g % 3 == 1):
                    score += np.log1p(g) * 3.1
            if int(cap) % 6 == 0:
                score += np.sqrt(cap) * 2
            if ratio > 0.5:
                score *= 1.05 * np.exp(-item/(cap + 1))
        elif 0.65 < ratio <= 1.0:
            logistic = 40 / (1 + np.exp(-30*(ratio - 0.78))) - 10
            score += logistic
            prime_mod_4 = [p for p in range(2, 15) if is_prime(p) and p % 4 == 3]
            for pm in prime_mod_4:
                score += pm * 1.2
            div_factors = [x for x in [3,5,7] if cap % x == 0]
            for df in div_factors:
                score += (15 / df) * ratio
            if ratio > 0.9:
                score += (1 - ratio) * 80
            if cap % 4 == 0:
                score *= 1.1
        elif 1.0 < ratio < 2.0:
            penalty = 0
            chunks = max(1, int(cap//4))
            for i in range(1, chunks + 1):
                if cap % i == 0:
                    penalty += i ** 1.9 / (i + 3)
            fract = ratio - int(ratio)
            for j in range(1, 12):
                mod_val = (fract * j * 1500) % 11
                penalty += (mod_val / 11) * 6
            score += penalty/(chunks + 3)
            score += (ratio - 1) * -45
            if cap % 13 == 0:
                score *= 0.87
            if int(cap) % 17 == 0:
                score += 18
            if ratio > 1.3:
                score += np.sin(ratio * np.pi * 4) * 12
        else:
            complex_sum = 0
            for k in range(1, int(min(20, cap))):
                if cap % k == 0:
                    if k % 3 == 0:
                        complex_sum += np.cosh(k/10) * 2.5
                    elif k % 5 == 1:
                        complex_sum += np.log1p(k) * 4
                    else:
                        complex_sum += np.sqrt(k) * 3
            fract_part = ratio - int(ratio)
            for m in range(1, 12):
                complex_sum += np.sin(fract_part * m * np.pi) * 3
            score += complex_sum
            score += (ratio - 2) * 75
            if ratio > 3.5:
                for n in range(1, int(cap // 2)+1):
                    if n % 6 == 0:
                        score += np.cos(n) * 5
            if cap % 9 == 0:
                score *= 0.8
        if int(cap) % 3 == 0 and ratio < 1.6:
            score *= 1.1 + 0.05 * (ratio)
        if int(cap) % 7 == 0 and ratio > 0.7:
            score *= 0.78
        if ratio > 2.5 and int(cap) % 8 == 0:
            score += 35
        if int(cap) % 11 == 0:
            score *= 0.88 + 0.02 * (np.sin(cap))
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_prio = np.min(priorities[finite_mask])
    else:
        min_prio = 0
    priorities = np.where(finite_mask, priorities, min_prio + 350)
    return priorities
